  "inlineSchema": "// prisma/schema.prisma\n// Marketplace Infographic Generation System + Freelance Scanner\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ============================================\n// SCANNER - Модели для сканера фриланс-заказов\n// ============================================\n\nmodel ScannerSource {\n  id            Int        @id @default(autoincrement())\n  name          String     @unique\n  type          SourceType\n  url           String\n  isActive      Boolean    @default(true)\n  scanInterval  Int        @default(900) // 15 минут для GitHub Actions\n  rateLimit     Int        @default(60)\n  lastScannedAt DateTime?\n  createdAt     DateTime   @default(now())\n  updatedAt     DateTime   @updatedAt\n\n  scannerJobs ScannerJob[]\n\n  @@index([name])\n  @@index([type])\n}\n\nenum SourceType {\n  WEBSITE\n  TELEGRAM\n  API\n  RSS\n}\n\nmodel ScannerJob {\n  id         Int           @id @default(autoincrement())\n  externalId String?\n  sourceId   Int\n  source     ScannerSource @relation(fields: [sourceId], references: [id])\n\n  // Данные заказа\n  url         String  @unique\n  title       String\n  description String? @db.Text\n  priceMin    Int?\n  priceMax    Int?\n\n  // AI анализ\n  aiScore    Int     @default(0)\n  aiReason   String? @db.Text\n  isSuitable Boolean @default(false)\n\n  // Статус\n  status ScannerJobStatus @default(NEW)\n\n  // Временные метки\n  scrapedAt   DateTime  @default(now())\n  processedAt DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  notifications ScannerNotification[]\n\n  @@index([sourceId])\n  @@index([status])\n  @@index([isSuitable])\n  @@index([scrapedAt])\n}\n\nenum ScannerJobStatus {\n  NEW\n  PROCESSING\n  READY\n  REJECTED\n  SENT\n  FAILED\n}\n\nmodel ScannerNotification {\n  id    Int        @id @default(autoincrement())\n  jobId Int\n  job   ScannerJob @relation(fields: [jobId], references: [id])\n\n  userId     String\n  telegramId BigInt\n  message    String @db.Text\n\n  status       NotificationStatus @default(PENDING)\n  sentAt       DateTime?\n  errorMessage String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([jobId])\n  @@index([telegramId])\n  @@index([status])\n}\n\nenum NotificationStatus {\n  PENDING\n  SENT\n  FAILED\n}\n\n// ============================================\n// USER SETTINGS - Настройки фильтров пользователя\n// ============================================\n\nmodel UserSettings {\n  id         Int      @id @default(autoincrement())\n  telegramId BigInt   @unique\n  keywords   String[]\n  minPrice   Int?\n  maxPrice   Int?\n  enabled    Boolean  @default(true)\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  @@index([telegramId])\n  @@map(\"UserSettings\")\n}\n",
